import tetotestMeta from '../tests/tetotest/meta';
import tetotestResults from '../tests/tetotest/resultDescriptions';
import tetotestImages from '../tests/tetotest/resultImages';

import sociopathMeta from '../tests/sociopathtest/meta';
import sociopathResults from '../tests/sociopathtest/resultDescriptions';
import sociopathImages from '../tests/sociopathtest/resultImages';

// 테스트 목록
const testResultSets = [
  {
    meta: tetotestMeta,
    results: tetotestResults,
    images: tetotestImages,
  },
  {
    meta: sociopathMeta,
    results: sociopathResults,
    images: sociopathImages,
  },
];

export default function TestsResults() {
  return (
    <div className="max-w-2xl mx-auto p-6 pb-16">
      <h1 className="text-3xl font-bold mb-7 text-emerald-700">테스트별 결과 유형 모아보기</h1>
      <p className="mb-10 text-gray-600">
        각 테스트의 결과 유형과 해설, 이미지를 한 번에 볼 수 있어요.<br />
        구글/사용자 모두 실제 컨텐츠를 확인할 수 있습니다.
      </p>
      {testResultSets.map(({ meta, results, images }, i) => (
        <section key={meta.id} className="mb-12">
          <h2 className="text-2xl font-bold mb-3 text-emerald-900">{meta.title}</h2>
          <div className="grid gap-7">
            {results.map((res, idx) => (
              <div key={res.id} className="flex items-center bg-gray-50 rounded-xl shadow p-4 gap-4">
                <img
                  src={images[idx]}
                  alt={res.name}
                  className="w-20 h-20 object-cover rounded-xl border-2 border-emerald-200 bg-white"
                />
                <div>
                  <div className="font-bold text-lg mb-1 text-emerald-800">{res.name}</div>
                  <div className="text-gray-600 text-sm">{res.description}</div>
                </div>
              </div>
            ))}
          </div>
        </section>
      ))}
    </div>
  );
}
